module top_module(
    input wire VPWR,
    output reg obf_VGND,
    output reg VPB,
    output reg VNB
);always @(*) begin
        if(VPWR == 1'b1) begin
            obf_VGND = 1'b0;
            VPB = 1'b1;
            VNB = 1'b0;
        end else begin
            obf_VGND = 1'b1;
            VPB = 1'b0;
            VNB = 1'b1;
        end
    end

endmodule
